using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=5e4+5;
double x[20],y[20],f[20][MAXN];
int n;
double dis(int a,int b)
{
	return sqrt((x[a]-x[b])*(x[a]-x[b])+(y[a]-y[b])*(y[a]-y[b]));
}
signed main(void)
{
	n=read();
	FOR(i,1,n)
    {
        scanf("%lf%lf",&x[i],&y[i]);
    }
	memset(f,127,sizeof(f));
	FOR(s,1,(1<<n)-1)
	{
		FOR(i,1,n)
		{
			if((s&(1<<(i-1)))==0)continue;
			if(s==(1<<(i-1)))
			{
				f[i][s]=0;
				continue;
			}
			FOR(j,1,n)
			{
				if((s&(1<<(j-1)))==0||i==j)continue;
				f[i][s]=min(f[i][s],f[j][s-(1<<(i-1))]+dis(i,j));
			}
		}
	}
	double ans=inf;
	FOR(i,1,n)
	{
		ans=min(ans,f[i][(1<<n)-1]+dis(i,0));
	}
	printf("%.2f\n",ans);
	return false;
}
